def solve(arg1: str, arg2: int) -> dict:
    # Validate inputs
    if not isinstance(arg1, str) or not isinstance(arg2, int):
        raise ValueError("Invalid input types")

    # Initialize the result dictionary
    result = {'intensity': 0, 'listenability': True}

    # Simulate the infusion of frequencies based on intensity
    if arg2 < 0:
        result['intensity'] = 0
    elif arg2 > 100:
        result['intensity'] = 100
    else:
        result['intensity'] = arg2

    # Determine listenability based on intensity
    if arg1 == "silent_track.mp3":
        result['intensity'] = 0
    elif arg1 == "noisy_track.mp3":
        result['listenability'] = False if result['intensity'] > 50 else True

    return result
